```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>
#include <stdexcept>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  auto conn = sqlgen::sqlite::connect(db_path);
  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  auto result = conn.and_then([&records](auto&& conn) {
    return sqlgen::insert(records).exec(conn);
  });

  if (!result) {
    throw std::runtime_error("Failed to insert records into table: " + table_name);
  }
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const T& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path);
  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  // Map table names to their primary key columns
  static const std::map<std::string, std::string> primary_keys = {
    {"Student", "SNo"},
    {"Course", "CID"}, 
    {"Score", "ScID"},
    {"Major", "MID"}
  };

  auto it = primary_keys.find(table_name);
  if (it == primary_keys.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  const std::string& pk_column = it->second;
  std::string sql = "UPDATE " + table_name + " SET " + col_name + " = ? WHERE " + pk_column + " = ?";

  auto result = conn.and_then([&sql, &new_value, record_id](auto&& conn) {
    return sqlgen::exec(conn, sql, new_value, record_id);
  });

  if (!result) {
    throw std::runtime_error("Failed to modify record in table: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  auto conn = sqlgen::sqlite::connect(db_path);
  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  // Map table names to their primary key columns
  static const std::map<std::string, std::string> primary_keys = {
    {"Student", "SNo"},
    {"Course", "CID"},
    {"Score", "ScID"}, 
    {"Major", "MID"}
  };

  auto it = primary_keys.find(table_name);
  if (it == primary_keys.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  const std::string& pk_column = it->second;
  std::string sql = "DELETE FROM " + table_name + " WHERE " + pk_column + " = ?";

  auto result = conn.and_then([&sql, &record_id](auto&& conn) {
    return sqlgen::exec(conn, sql, record_id);
  });

  if (!result) {
    throw std::runtime_error("Failed to delete record from table: " + table_name);
  }
}
```

Key implementation details:

1. **`add_eas_records`**: Uses `sqlgen::insert()` with the provided records vector and executes it on the database connection.

2. **`modify_eas_records_by_id`**: 
   - Creates a mapping of table names to their primary key columns
   - Builds a parameterized SQL UPDATE statement
   - Uses `sqlgen::exec()` with parameters to safely execute the update

3. **`delete_eas_records_by_id`**:
   - Similar to modify, but builds a DELETE statement
   - Handles the record_id as a string to accommodate different primary key types

All functions:
- Connect to the database using the predefined `db_path`
- Handle errors by throwing `std::runtime_error` with descriptive messages
- Use parameterized queries to prevent SQL injection
- Include proper error checking for database operations

