namespace delete_inactive_users {

TEST(sqlite, delete_inactive_users) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<User>(conn);
  create_table<User>(conn);

  std::vector<User> users = {
      {1, "active_recent", "2025-07-01 00:00:00", "active"},
      {2, "inactive_old", "2023-01-01 00:00:00", "active"},
      {3, "inactive_older", "2022-12-31 00:00:00", "active"}};
  insert(conn, users);

  ASSERT_TRUE(delete_inactive_users());

  const auto remaining = sqlgen::read<std::vector<User>>(conn).value();
  ASSERT_EQ(remaining.size(), 1u);
  EXPECT_EQ(remaining[0].user_id.value(), 1);
}

