```cpp
#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    sqlgen::PrimaryKey<std::string> SNo;
    rfl::Field<"SName", std::string> SName;
    rfl::Field<"Sex", std::optional<int>> Sex = 1;
    rfl::Field<"Birthday", std::optional<std::string>> Birthday;
    rfl::Field<"Major", std::optional<int>> Major;
    rfl::Field<"Scorses", std::optional<float>> Scorses = 0.0f;
    rfl::Field<"Remark", std::optional<std::string>> Remark;
  };

  struct Course {
    sqlgen::PrimaryKey<sqlgen::AutoIncrement<int>> CID;
    rfl::Field<"CName", std::string> CName;
    rfl::Field<"Term", std::optional<int>> Term = 1;
    rfl::Field<"CTime", std::optional<int>> CTime;
    rfl::Field<"Credit", float> Credit = 0.0f;
  };

  struct Score {
    rfl::Field<"SNo", std::string> SNo;
    rfl::Field<"CID", int> CID;
    rfl::Field<"Score", std::optional<float>> Score;
  };

  void design_eas_database() {
    // Remove existing database file if it exists
    std::filesystem::remove("test_db.sqlite");

    // Create database connection
    auto db = sqlgen::sqlite::Database("test_db.sqlite");

    // Create Student table
    db.create_table<Student>(sqlgen::TableOptions{
        .if_not_exists = true
    });

    // Create Course table
    db.create_table<Course>(sqlgen::TableOptions{
        .if_not_exists = true
    });

    // Create Score table with composite primary key and foreign keys
    // Note: sqlgen doesn't directly support composite PKs in struct definition,
    // so we need to create this table with custom SQL
    db.execute(R"(
        CREATE TABLE IF NOT EXISTS Score (
            SNo VARCHAR(10) NOT NULL,
            CID INTEGER NOT NULL,
            Score REAL,
            PRIMARY KEY (SNo, CID),
            FOREIGN KEY (SNo) REFERENCES Student(SNo),
            FOREIGN KEY (CID) REFERENCES Course(CID)
        )
    )");
  }

}
