namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  // View to store course enrollment statistics
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    // Create Course table if not exists
    .and_then(create_table<Course> | if_not_exists)
    // Create Enrollment table if not exists  
    .and_then(create_table<Enrollment> | if_not_exists)
    // Query for course enrollment statistics
    .and_then([](auto&& conn) {
      // Build the query using sqlgen's query builder
      auto query = select(columns(
        "c.title"_c,
        count("e.enrollment_id"_c).as("student_count"),
        avg("e.grade"_c).as("avg_grade")
      ))
      .from<Course>("c")
      .left_join<Enrollment>("e").on("c.course_id"_c == "e.course_id"_c)
      .group_by("c.course_id"_c, "c.title"_c);

      return query | conn;
    })
    // Read the results into CourseStats objects
    .and_then(read<std::vector<CourseStats>>);

  // Return the results or empty vector on error
  if (result) {
    return std::move(*result);
  } else {
    // Return empty vector if there was an error
    return {};
  }
}

}  // namespace query_course_enrollment_stats
```

