```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_customer_purchase_history {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
  std::string email;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  sqlgen::ForeignKey<int, Customer, "customer_id"> customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  double total_amount;
};

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  sqlgen::ForeignKey<int, Order, "order_id"> order_id;
  sqlgen::ForeignKey<int, Product, "product_id"> product_id;
  int quantity;
};

struct PurchaseHistory {
  std::string product_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  int quantity;
};


/**
 * Function: Retrieve a customer's purchase history with product details.
 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables if they don't exist
  conn.create_table<Customer>();
  conn.create_table<Product>();
  conn.create_table<Order>();
  conn.create_table<OrderItem>();

  // Build the query using sqlgen's query builder
  using namespace sqlgen::literals;

  auto results = conn.query(R"(
    SELECT p.name as product_name, o.order_date, oi.quantity
    FROM Customer c
    JOIN "Order" o ON c.customer_id = o.customer_id
    JOIN OrderItem oi ON o.order_id = oi.order_id
    JOIN Product p ON oi.product_id = p.product_id
    WHERE c.customer_id = ?
    ORDER BY o.order_date DESC
  )"_sql, customer_id);

  // Convert the results to PurchaseHistory objects
  std::vector<PurchaseHistory> purchase_history;

  for (const auto& row : results) {
    purchase_history.push_back(PurchaseHistory{
      .product_name = std::get<0>(row),
      .order_date = std::get<1>(row),
      .quantity = std::get<2>(row)
    });
  }

  return purchase_history;
}

}  // namespace query_customer_purchase_history
```

This implementation:

1. **Connects to the SQLite database** using `sqlgen::sqlite::connect("test_db.sqlite")`
2. **Creates all necessary tables** using `conn.create_table<T>()` for each struct
3. **Executes the SQL query** using `conn.query()` with a raw SQL string and parameter binding (`?` placeholder)
4. **Converts results to PurchaseHistory objects** by iterating through the query results
5. **Returns the purchase history** as a vector of `PurchaseHistory` structs

The query matches the reference SQL exactly, joining all four tables and filtering by the customer ID. The results are ordered by order date in descending order as specified.

