  int unique_pages;
};

/**
 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  sqlgen::sqlite::Database db;
  db.connect("test_db.sqlite");

  // Build the query using sqlgen DSL
  auto query = select(strftime("%Y-%m-%d", PageVisit::visit_time).as("visit_date"),
                     count().as("total_visits"),
                     count(distinct(PageVisit::url)).as("unique_pages"))
              .from<PageVisit>()
              .group_by(strftime("%Y-%m-%d", PageVisit::visit_time))
              .order_by(strftime("%Y-%m-%d", PageVisit::visit_time));

  // Execute the query and return results
  return db.select<DailyTraffic>(query);
}

}  // namespace query_daily_traffic_metrics
