```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_high_value_orders {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct OrderView {
  static constexpr const char* tablename = "HighValueOrderView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string name;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

std::vector<OrderView> query_high_value_orders() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open the database connection
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Build the query using sqlgen's query builder
  auto query = select(
      columns(
          column<Order>(&Order::order_id),
          column<Customer>(&Customer::name),
          column<Order>(&Order::total_amount),
          column<Order>(&Order::order_date)
      ),
      from<Order>(),
      join<Customer>(on<Order, Customer>(&Order::customer_id, &Customer::customer_id)),
      where(greater_than(column<Order>(&Order::total_amount), 1000.0)),
      order_by(column<Order>(&Order::total_amount), order::desc)
  );

  // Execute the query and return results
  return db.query<OrderView>(query);
}

}  // namespace query_high_value_orders
```

