namespace query_product_sales_report {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create the query using sqlgen's fluent interface
    auto query = sqlgen::read<CategoryReport> 
                | sqlgen::from<Product, Sale>()
                | sqlgen::join<Sale>(&Product::product_id == &Sale::product_id)
                | sqlgen::group_by(&Product::category)
                | sqlgen::having(sqlgen::sum(&Sale::amount) > 5000);

    // Execute the query against the SQLite database
    return sqlgen::sqlite::read<CategoryReport>("test_db.sqlite", query);
}

}  // namespace query_product_sales_report
```

The implementation uses sqlgen's fluent interface to build the query:

1. `sqlgen::read<CategoryReport>` - Specifies we want to read into CategoryReport structs
2. `sqlgen::from<Product, Sale>()` - Specifies the tables to query from
3. `sqlgen::join<Sale>(&Product::product_id == &Sale::product_id)` - Creates the INNER JOIN condition
4. `sqlgen::group_by(&Product::category)` - Groups by the category field
5. `sqlgen::having(sqlgen::sum(&Sale::amount) > 5000)` - Applies the HAVING clause filter

The query is then executed against the SQLite database "test_db.sqlite" using `sqlgen::sqlite::read<CategoryReport>()`, which returns a vector of CategoryReport objects containing the aggregated results.

