  if (!conn) {
    return false;
  }

  // Use transaction to ensure atomicity
  return conn->transaction([&]() -> bool {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // First, check if sender has sufficient funds
    auto sender_account = conn->read<Account>(
        "account_id"_c == from_account_id
    );

    if (sender_account.empty() || sender_account[0].balance < amount) {
      // Insufficient funds or account not found
      return false;
    }

    // Deduct from sender
    auto update_sender = conn->update<Account>(
        "balance"_c = "balance"_c - amount,
        "account_id"_c == from_account_id
    );

    if (!update_sender) {
      return false;
    }

    // Add to receiver
    auto update_receiver = conn->update<Account>(
        "balance"_c = "balance"_c + amount,
        "account_id"_c == to_account_id
    );

    if (!update_receiver) {
      return false;
    }

    // All operations successful
    return true;
  });
}

