#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
   // Connect to the SQLite database
   sqlgen::SQLiteDB db("test_db.sqlite");

   // First update: pending orders older than 7 days to expired
   auto expired_update = db.update<Order>()
       .set(&Order::status, "expired")
       .where(sqlgen::compare(&Order::status, "pending") && 
              sqlgen::expr("order_date < DATE('now', '-7 days')"));
   int expired_count = expired_update.execute();

   // Second update: shipped orders to delivered (simulating delivery confirmation)
   auto delivered_update = db.update<Order>()
       .set(&Order::status, "delivered")
       .where(sqlgen::compare(&Order::status, "shipped"));
   int delivered_count = delivered_update.execute();

   // Return total number of rows affected
   return expired_count + delivered_count;
}

} // namespace update_order_status
```

