};

bool upsert_user_profile(const UserProfile& u) {
  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite");
  if (!conn) return false;

  create_table<UserProfile>(conn);

  // Insert using sqlgen::insert_or_replace for PK/Unique presence
  return insert_or_replace(std::vector{u})(conn).has_value();
