#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_view_sales_summary {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  static constexpr const char* viewname = "SalesSummary";
  static constexpr bool is_view = true;
  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Build the SELECT query for the view using sqlgen's query builder
  auto query = select(
      alias<"product_name">(&Product::name),
      alias<"total_quantity">(sum(&Sale::quantity)),
      alias<"total_revenue">(sum(&Sale::amount))
  ).from<Sale>()
   .join<Product>(on(&Sale::product_id, &Product::product_id))
   .group_by(&Product::name);

  // Create the view using create_view with if_not_exists
  auto result = conn.and_then(create_view<SalesSummary>(query) | if_not_exists);

  return result.has_value();
}

}  // namespace schema_create_view_sales_summary
```

