 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    // Return empty vector if connection fails
    return {};
  }

  // Since SQLite doesn't support RIGHT JOIN directly, we simulate it with LEFT JOIN
  // RIGHT JOIN departments projects is equivalent to LEFT JOIN projects departments
  // We need to create a custom query structure for the join result
  struct JoinResult {
    std::optional<std::string> department_name;
    std::string project_name;
  };

  auto result = conn->and_then(
    sqlgen::read<std::vector<JoinResult>> |
    join<left_join>(&Project::department_id, &Department::department_id) |
    select("Department.name"_c.as("department_name"), "Project.name"_c.as("project_name"))
  );

  if (result) {
