Here's the complete implementation of the `analyze_temporal_data` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
    using namespace sqlgen;
    using namespace sqlgen::sqlite;

    // Create connection to SQLite database
    Connection conn("test_db.sqlite");

    // Create temporary table for events
    conn.execute(R"(
        CREATE TEMPORARY TABLE IF NOT EXISTS Event (
            event_id INTEGER PRIMARY KEY,
            event_name TEXT NOT NULL,
            start_time DATETIME NOT NULL,
            end_time DATETIME,
            created_at DATETIME NOT NULL
        )
    )");

    // Clear any existing data from temporary table
    conn.execute("DELETE FROM Event");

    // Insert events into the temporary table
    for (const auto& event : events) {
        auto insert_query = Insert<Event>{event};
        conn.execute(to_sql(insert_query));
    }

    // Execute the temporal analysis query
    const char* analysis_query = R"(
        SELECT 
            event_id,
            event_name,
            CAST(strftime('%d', start_time) AS INTEGER) as start_day,
            CAST(strftime('%m', start_time) AS INTEGER) as start_month,
            CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
            CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
            CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
            CAST(strftime('%S', start_time) AS INTEGER) as start_second,
            CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
            CAST(strftime('%s', start_time) AS INTEGER) as start_epoch,
            CASE 
                WHEN end_time IS NOT NULL 
                THEN JULIANDAY(end_time) - JULIANDAY(start_time)
                ELSE NULL 
            END as duration_days
        FROM Event
        WHERE end_time IS NOT NULL
    )";

    auto result = conn.execute(analysis_query);
    std::vector<TemporalAnalysis> analysis_results;

    // Process each row of the result set
    for (const auto& row : result) {
        TemporalAnalysis analysis;
        analysis.event_id = row[0].get<int>();
        analysis.event_name = row[1].get<std::string>();
        analysis.start_day = row[2].get<int>();
        analysis.start_month = row[3].get<int>();
        analysis.start_year = row[4].get<int>();
        analysis.start_hour = row[5].get<int>();
        analysis.start_minute = row[6].get<int>();
        analysis.start_second = row[7].get<int>();
        analysis.start_weekday = row[8].get<int>();
        analysis.start_epoch = row[9].get<int64_t>();

        // Handle optional duration_days
        if (!row[10].is_null()) {
            analysis.duration_days = row[10].get<double>();
        }

        analysis_results.push_back(analysis);
    }

    return analysis_results;
}

}  // namespace analyze_temporal_data
```

Key implementation details:

1. **Database Connection**: Creates a connection to the SQLite database "test_db.sqlite" using `sqlgen::sqlite::Connection`.

2. **Temporary Table**: Creates a temporary table to store the events, which automatically gets cleaned up when the connection closes.

3. **Data Insertion**: Uses `sqlgen::Insert` to insert each event into the temporary table with proper type mapping.

4. **Temporal Analysis Query**: Implements the required SQL query using SQLite's date/time functions:
   - `strftime()` for extracting date components
   - `strftime('%s')` for Unix epoch conversion  
   - `JULIANDAY()` for calculating day differences
   - Proper casting and NULL handling for optional fields

5. **Result Processing**: Iterates through the query results and maps them to `TemporalAnalysis` structs, handling optional fields appropriately.

The function returns a comprehensive temporal analysis of all events that have both start and end times, including all the required date/time components and calculations.

