    JOIN User u2 ON f1.user2_id = u2.user_id
    JOIN Friendship f2 ON u2.user_id = f2.user1_id
    JOIN User u3 ON f2.user2_id = u3.user_id
    WHERE u1.user_id != u3.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user1_id = u1.user_id AND f3.user2_id = u3.user_id
      )
    ORDER BY u1.username, u3.username;
  )");

  auto friend_of_friend = friend_of_friend_query.execute();
  for (const auto& row : friend_of_friend) {
    FriendConnection conn;
    conn.user1_name = row[0];
    conn.user2_name = row[1];
    results.push_back(conn);
    std::cout << "Friend of friend: " << row[0] << " -> " << row[1] << "\n";
  }

  // 4. Count friends per user and identify most connected users
  auto friend_count_query = db.prepare(R"(
    SELECT u.username, COUNT(f.user1_id) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user1_id
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC;
  )");

  auto friend_counts = friend_count_query.execute();
  for (const auto& row : friend_counts) {
    std::cout << "Friend count: " << row[0] << " has " << row[1] << " friends\n";
  }

  // 5. Find users in the same city who are not yet friends
  auto same_city_recommendation_query = db.prepare(R"(
    SELECT u1.username, u2.username
    FROM User u1, User u2
    WHERE u1.city = u2.city 
      AND u1.user_id < u2.user_id
      AND u1.city IS NOT NULL 
      AND u2.city IS NOT NULL
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f 
        WHERE (f.user1_id = u1.user_id AND f.user2_id = u2.user_id)
           OR (f.user1_id = u2.user_id AND f.user2_id = u1.user_id)
      )
    ORDER BY u1.city, u1.username, u2.username;
  )");

  auto same_city_recommendations = same_city_recommendation_query.execute();
  for (const auto& row : same_city_recommendations) {
    std::cout << "Same city recommendation: " << row[0] << " and " << row[1] << "\n";
  }

  return results;
}

}  // namespace analyze_social_network

