```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <cassert>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Enable foreign key constraints (required for SQLite)
  conn.execute("PRAGMA foreign_keys = ON");

  // Drop tables if they exist to start fresh
  conn.execute("DROP TABLE IF EXISTS Child");
  conn.execute("DROP TABLE IF EXISTS Parent");

  // Create Parent table
  conn.createTable<Parent>();

  // Create Child table with foreign key constraint
  // The foreign key will automatically have ON DELETE CASCADE due to sqlgen's ForeignKey type
  conn.createTable<Child>();

  // Insert parent record
  Parent parent{1, "Test Parent"};
  conn.insert(parent);

  // Insert child records with the same parent_id
  std::vector<Child> children = {
    {1, 1, "First child"},
    {2, 1, "Second child"},
    {3, 1, "Third child"}
  };

  for (const auto& child : children) {
    conn.insert(child);
  }

  // Verify children were inserted
  auto children_before_delete = conn.select<Child>().where(Child::parent_id == 1).execute();
  assert(children_before_delete.size() == 3 && "Should have 3 children before delete");

  // Delete the parent (this should cascade delete the children)
  conn.delete_<Parent>().where(Parent::parent_id == 1).execute();

  // Verify parent was deleted
  auto parents_after_delete = conn.select<Parent>().where(Parent::parent_id == 1).execute();
  assert(parents_after_delete.empty() && "Parent should be deleted");

  // Verify children were automatically deleted due to cascade
  auto children_after_delete = conn.select<Child>().where(Child::parent_id == 1).execute();

  // Clean up
  conn.execute("DROP TABLE IF EXISTS Child");
  conn.execute("DROP TABLE IF EXISTS Parent");

  // Return verification result
  return children_after_delete.empty();
}

}  // namespace cascade_delete_demo
```

