                    .left_join<Product>("p").on("s.supplier_id"_c == "p.supplier_id"_c);

    // Second part: RIGHT JOIN (simulated by swapping tables in LEFT JOIN)
    auto right_join = select("s.name"_c.as("supplier_name"), 
                            "p.name"_c.as("product_name"))
                     .from<Product>("p")
                     .left_join<Supplier>("s").on("p.supplier_id"_c == "s.supplier_id"_c)
                     .where("s.supplier_id"_c.is_null()); // Only get rows where supplier doesn't exist

    // Combine both parts with UNION
    auto full_join = left_join.union_(right_join);

    return read<std::vector<SupProd>>(full_join);
  });

  return result.value();
}

}  // namespace full_join_suppliers_products

