```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Create tables
  db.and_then(create_table<Department> | if_not_exists).value();
  db.and_then(create_table<Employee> | if_not_exists).value();

  // Clear existing data and insert new data
  db.and_then(remove_all<Department>).value();
  db.and_then(remove_all<Employee>).value();
  db.and_then(insert(depts)).value();
  db.and_then(insert(emps)).value();

  JoinAnalysis analysis;

  // INNER JOIN: Employees with assigned departments
  auto inner_join_query = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "INNER JOIN Employee e ON d.department_id = e.department_id";

  auto inner_results = db.and_then(raw_query<JoinResult>(inner_join_query));
  if (inner_results.has_value()) {
    analysis.inner_join_results = inner_results.value();
  }

  // LEFT JOIN: All employees (even without departments)
  auto left_join_query = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id";

  auto left_results = db.and_then(raw_query<JoinResult>(left_join_query));
  if (left_results.has_value()) {
    analysis.left_join_results = left_results.value();
  }

  // RIGHT JOIN: All departments (even without employees) - emulated with LEFT JOIN
  auto right_join_query = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id";

  auto right_results = db.and_then(raw_query<JoinResult>(right_join_query));
  if (right_results.has_value()) {
    analysis.right_join_results = right_results.value();
  }

  // FULL JOIN: All employees and departments - emulated with UNION
  auto full_join_query = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id "
      "UNION ALL "
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id "
      "WHERE e.employee_id IS NULL";

  auto full_results = db.and_then(raw_query<JoinResult>(full_join_query));
  if (full_results.has_value()) {
    analysis.full_join_results = full_results.value();
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlgen::sqlite::connect()`
2. **Creates the required tables** using `create_table` with `if_not_exists` modifier
3. **Inserts the provided data** after clearing existing records
4. **Performs all four join types**:
   - **INNER JOIN**: Gets employees with assigned departments
   - **LEFT JOIN**: Includes all employees (even without departments)
   - **RIGHT JOIN**: Includes all departments (even without employees) - emulated using LEFT JOIN
   - **FULL JOIN**: Includes all employees and departments - emulated using UNION
5. **Returns comprehensive analysis** with results from all join operations stored in the `JoinAnalysis` structure

The code handles optional values properly since outer joins can result in NULL values, and uses the `sqlgen` library's query execution capabilities to run the SQL statements and map results to the `JoinResult` structure.

