                      WhereType, GroupByType, OrderByType, LimitType, ToType>{
        .fields_ = _s.fields_,
        .from_ = _s.from_,
        .joins_ = NewJoinsType(_join)};

  } else {
    using TupleType =
        rfl::Tuple<transpilation::Join<OtherTableOrQueryType, ConditionType,
                                       _alias, _how>>;

    const auto joins = rfl::tuple_cat(_s.joins_, TupleType(_join));

