```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace create_view_order_summary {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
};

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  double unit_price;
  int quantity;
};

struct OrderSummary {
  static constexpr const char* tablename = "OrderSummaryView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
  double total;
};

/**
 * Description: This function demonstrates creating a view.
 * Returns: std::vector<OrderSummary>.
 */
std::vector<OrderSummary> create_view_order_summary() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to SQLite database
    sqlgen::sqlite::Database db("test_db.sqlite");

    // Create the view using CREATE VIEW AS
    auto view = create_view_as<OrderSummary>(db,
        select<OrderSummary>(
            &Order::order_id,
            &Order::customer,
            sqlgen::sum(&OrderItem::unit_price * &OrderItem::quantity).as(&OrderSummary::total)
        )
        .from<Order>()
        .join<OrderItem>(&Order::order_id == &OrderItem::order_id)
        .group_by(&Order::order_id, &Order::customer)
    );

    // Read from the view to verify data
    auto results = select_from<OrderSummary>().run(db);

    return results;
}

}  // namespace create_view_order_summary
```

