```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::Database("test_db.sqlite");

  // Create a query to extract weekday and aggregate totals
  // Using strftime with '%w' to get weekday (0-6, where 0 is Sunday)
  auto query = sqlgen::Select<
      sqlgen::expr::Function<"strftime", "%w", &Sales::sale_time>.as("weekday"),
      sqlgen::expr::Sum<&Sales::quantity>.as("total_quantity")
  >{}.from<Sales>().group_by(sqlgen::expr::Function<"strftime", "%w", &Sales::sale_time>);

  // Execute the query and get results
  auto results = db.execute(query).value();

  // Convert results to WeekdayStats vector
  std::vector<WeekdayStats> stats;
  for (const auto& row : results) {
    WeekdayStats stat;
    stat.weekday = std::stoi(row.weekday); // Convert string weekday to int
    stat.total_quantity = row.total_quantity;
    stats.push_back(stat);
  }

  return stats;
}

}  // namespace weekday_sales_analysis
```

