```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto db = SQLite::open("test_db.sqlite");

  // Build the query with GROUP BY and aggregations
  auto results = db->select(
      &User::user_id, 
      &User::name, 
      count(&Post::post_id).as("post_count"),
      avg(length(&Post::content)).as("avg_length")
    )
    .from<User>()
    .join<Post>(on(&User::user_id == &Post::user_id))
    .group_by(&User::user_id, &User::name)
    .template get<Stats>();

  return results;
}

}  // namespace group_by_with_aggregations
```

