    std::string sql = sqlgen::sqlite::to_sql(query);

    EXPECT_TRUE(sql.find("CREATE TABLE") != std::string::npos);
    EXPECT_TRUE(sql.find("Target") != std::string::npos);
    EXPECT_TRUE(sql.find("AS SELECT") != std::string::npos || sql.find("AS") != std::string::npos);
    EXPECT_TRUE(sql.find("FROM") != std::string::npos);
    EXPECT_TRUE(sql.find("Source") != std::string::npos);
